import{_ as t,o as i,c as l,ag as e}from"./chunks/framework.DXGyWiRo.js";const r="/media/202509/2025-09-19_151628_1218800.993778014257793.png",o="/media/202509/2025-09-19_151645_4323780.6785930276906712.png",d="/media/202509/2025-09-19_151725_5911600.9009532808510836.png",n="/media/202509/2025-09-19_151737_3099190.9152327649404424.png",s="/media/202509/2025-09-19_151828_9047920.9887597590541548.png",h="/media/202509/2025-09-19_151840_3129520.993306931384668.png",g=JSON.parse('{"title":"AC7911B 快速体验指南","description":"","frontmatter":{"title":"AC7911B 快速体验指南"},"headers":[],"relativePath":"hardware/ac7911b/quickstart.md","filePath":"hardware/ac7911b/quickstart.md","lastUpdated":null}'),c={name:"hardware/ac7911b/quickstart.md"};function p(_,a,m,u,b,q){return i(),l("div",null,[...a[0]||(a[0]=[e('<p>概述</p><p>AC7911B AIUI语音开发套件快速体验：</p><h1 id="物件准备" tabindex="-1">物件准备 <a class="header-anchor" href="#物件准备" aria-label="Permalink to &quot;物件准备&quot;">​</a></h1><ul><li>AC7911 套件</li><li>Micro USB数据线</li></ul><h1 id="小程序配网" tabindex="-1">小程序配网 <a class="header-anchor" href="#小程序配网" aria-label="Permalink to &quot;小程序配网&quot;">​</a></h1><h2 id="开机" tabindex="-1">开机 <a class="header-anchor" href="#开机" aria-label="Permalink to &quot;开机&quot;">​</a></h2><p>连接USB供电，将电源开关拨到ON状态开机。</p><h2 id="_2-2-进入配网模式" tabindex="-1">2.2. 进入配网模式 <a class="header-anchor" href="#_2-2-进入配网模式" aria-label="Permalink to &quot;2.2. 进入配网模式&quot;">​</a></h2><p>可以在设备未唤醒情况，直接说出离线识别命令词就可与套件进行交互。此模组默认支持以下离线识别命令词：</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>离线命令词</strong></td><td><strong>响应</strong></td></tr><tr><td>配网模式</td><td>进入配网模式</td></tr></tbody></table><h2 id="_2-3-配网小程序" tabindex="-1">2.3. 配网小程序 <a class="header-anchor" href="#_2-3-配网小程序" aria-label="Permalink to &quot;2.3. 配网小程序&quot;">​</a></h2><p>微信扫码登录”小飞陪伴”微信小程序。</p><p><img src="'+r+'" alt=""></p><h2 id="_2-4-配网步骤" tabindex="-1">2.4. 配网步骤 <a class="header-anchor" href="#_2-4-配网步骤" aria-label="Permalink to &quot;2.4. 配网步骤&quot;">​</a></h2><ul><li>步骤一：开发板上电，拨码开关开机后，语音喊：配网模式；</li><li>步骤二：微信打开”小飞陪伴”小程序；</li><li>步骤三：点击”设备”，添加设备；</li><li>步骤四：选择弹出的设备；</li><li>步骤五：输入wifi账号及密码；</li><li>步骤六：等待配网，配网成功开发板会有提示音。</li></ul><p><img src="'+o+'" alt=""></p><h3 id="其他小程序功能" tabindex="-1">其他小程序功能： <a class="header-anchor" href="#其他小程序功能" aria-label="Permalink to &quot;其他小程序功能：&quot;">​</a></h3><p><img src="'+d+'" alt=""></p><p><img src="'+n+'" alt=""></p><h1 id="交互方式" tabindex="-1">交互方式 <a class="header-anchor" href="#交互方式" aria-label="Permalink to &quot;交互方式&quot;">​</a></h1><ul><li>支持一次唤醒多次交互，交互停止60S后退出唤醒状态；</li><li>支持语音打断，全双工交互；</li><li>支持单双工交互切换；</li><li>支持按键打断当前对话。</li></ul><h1 id="固件更新说明" tabindex="-1">固件更新说明 <a class="header-anchor" href="#固件更新说明" aria-label="Permalink to &quot;固件更新说明&quot;">​</a></h1><ul><li>步骤一：准备一根typeC线束，typeC口接到7911主板，USB口连接电脑</li><li>步骤二：在烧录按键接口接上2pin1.25mm的按键（或者按键接口短接）</li><li>步骤三：按住烧录按键，同时打开拨码开关给主板上电（靠近模式切换按键处的灯亮红色），电脑会提示”叮咚”声进入烧录模式</li></ul><p><img src="'+s+'" alt=""></p><p>图 5 烧录模式接线示意图</p><ul><li>步骤四：点击待升级固件工具包内的download.bat（联系<a href="/faq/contact.html" title="技术支持">技术支持</a>获取），等待程序执行完毕，即可完成固件更新。</li></ul><p><img src="'+h+'" alt=""></p><p>图 6 固件烧录进程图</p>',28)])])}const k=t(c,[["render",p]]);export{g as __pageData,k as default};
